    int numberOfSubstrings(string s) {
        int count[3] = {0};
        int res = 0;
        for (char c : s) {
            count[c - 'a']++;
            if (count[0] && count[1] && count[2]) {
                res += s.size() - *max_element(count, count + 3) + 1;
            }
        }
        return res;
    }
};```
